// ============================ CAVERN 水晶洞窟 — ground decals + standing decor ============================
// Companion pack to the existing bd_cav_* family in src/art/biome_decor.js. Ground decals are
// LOW-CONTRAST floor variation (never outlined, never bright-teal glow — that reads as a pickup);
// standing decor follows the same construction recipe as bd_cav_cluster/stalagmite/rocks
// (soft ground shadow -> layered fill -> texture -> outline last).

// cavern floor palette anchors (matches biomes.js `cavern` entry exactly)
const cavF0 = '#1c2a2e';    // floor
const cavF1 = '#243638';    // floor2
const cavLine = '#121e20';  // grout / mortar line

// ---------------------------------------------------------------------------
// (a) ground decals — decal_cavern_* — flat, low-contrast, no outline
// ---------------------------------------------------------------------------

defineSprite('decal_cavern_crumble', 10, 6, (p) => {        // crumbled floor rubble
  p.ellipse(5, 4, 4, 2, darken(cavF0, 0.12));
  p.ellipse(3, 3, 2, 1.4, lighten(cavF0, 0.1));
  p.speckle(1, 2, 8, 3, darken(cavF1, 0.18), 5, 21);
  p.px(6, 2, lighten(cavF1, 0.14));
  p.px(8, 4, darken(cavLine, 0.05));
}, { anchor: 'center' });

defineSprite('decal_cavern_vein', 14, 5, (p) => {           // thin mineral vein streak
  p.line(1, 4, 6, 2, lighten(cavF0, 0.14));
  p.line(6, 2, 12, 3, lighten(cavF0, 0.1));
  p.px(4, 3, darken(cavF1, 0.1));
  p.px(9, 2, darken(cavF1, 0.1));
  p.speckle(1, 1, 12, 3, lighten(cavF1, 0.08), 3, 43);
}, { anchor: 'center' });

defineSprite('decal_cavern_puddle', 12, 7, (p) => {         // damp rock-water puddle
  p.ellipse(6, 5, 5, 2.4, darken(cavF0, 0.1));
  p.ellipse(6, 5, 4, 1.8, lighten(cavF1, 0.06));
  p.px(4, 4, lighten(cavF1, 0.16));
  p.px(8, 5, lighten(cavF1, 0.12));
  p.hline(3, 9, 6, darken(cavLine, 0.05));
}, { anchor: 'center' });

defineSprite('decal_cavern_shardbits', 10, 6, (p) => {      // scattered crystal shard debris (microglow #1)
  p.line(2, 5, 3, 2, darken(cavF1, 0.05));
  p.line(3, 2, 4, 5, lighten(cavF1, 0.1));
  p.line(7, 5, 8, 3, darken(cavF1, 0.02));
  p.speckle(1, 3, 8, 2, darken(cavF0, 0.1), 3, 12);
  p.glow(3, 3, 1.6, P.astral, 0.22, 2);                     // cool violet cast, NOT bright teal (avoids pickup confusion)
  p.px(3, 2, P.astralL); p.px(8, 3, P.white);
}, { anchor: 'center' });

defineSprite('decal_cavern_mossline', 12, 5, (p) => {       // dark lichen/algae patch
  p.ellipse(4, 3, 3, 1.6, darken(cavF1, 0.14));
  p.ellipse(8, 3, 2.6, 1.3, darken(cavF0, 0.12));
  p.speckle(1, 1, 10, 3, darken(cavF1, 0.18), 5, 67);
  p.px(5, 2, lighten(cavF1, 0.08));
}, { anchor: 'center' });

defineSprite('decal_cavern_pebbles', 9, 5, (p) => {         // small pebble cluster
  p.ellipse(2, 3, 1.4, 1, lighten(cavF1, 0.1));
  p.ellipse(5, 4, 1.6, 1.1, darken(cavF0, 0.1));
  p.ellipse(7, 3, 1.2, 0.9, lighten(cavF0, 0.14));
  p.px(2, 2, lighten(cavF1, 0.18));
  p.px(5, 3, darken(cavLine, 0.06));
}, { anchor: 'center' });

defineSprite('decal_cavern_drip', 7, 9, (p) => {            // mineral drip stain trailing down
  p.vline(0, 6, 3, darken(cavF1, 0.12));
  p.vline(1, 5, 4, darken(cavF1, 0.08));
  p.ellipse(3, 7, 2.4, 1.4, darken(cavF0, 0.1));
  p.px(3, 1, lighten(cavF1, 0.1));
}, { anchor: 'center' });

defineSprite('decal_cavern_glintdust', 11, 6, (p) => {      // fine glinting mineral dust (microglow #2)
  p.speckle(1, 2, 9, 3, lighten(cavF1, 0.12), 6, 88);
  p.glow(5, 3, 1.8, P.astral, 0.18, 2);                     // same cool violet/white treatment as shardbits
  p.px(3, 3, P.astralL); p.px(7, 2, P.white); p.px(5, 4, P.rimCool);
}, { anchor: 'center' });

// ---------------------------------------------------------------------------
// (b) standing decor — bdx_cavern_* — same recipe as bd_cav_cluster/stalagmite/rocks
// ---------------------------------------------------------------------------

defineAnim('bdx_cavern_shardlet', 14, 18, 2, (p, f) => {    // small twin crystal (cluster filler)
  p.softShadow(7, 17, 5, 1.8, 0.42);
  p.ellipse(7, 17, 5, 2, '#182a2c');
  p.line(7, 17, 5, 6, P.shardD); p.line(7, 17, 9, 5, P.shard); p.line(7, 17, 10, 9, P.shardD);
  p.line(6, 17, 5, 10, P.shardD); p.line(9, 17, 11, 11, P.shard);
  p.glow(8, 8, 2 + f, P.shard, 0.35, 3);
  p.px(9, 5, P.shardL); p.px(5, 8, lighten(P.shard, 0.15));
  if (f === 1) p.sparkle(9, 4, P.shardL, 1);
  p.outline(P.ink);
}, { anchor: 'feet', fps: 2 });

defineSprite('bdx_cavern_mossstone', 16, 14, (p) => {       // glowing moss-covered boulder
  p.softShadow(8, 13, 6, 1.8, 0.4);
  p.ellipse(8, 10, 7, 5, '#2e4a4e');
  p.ellipse(6, 8, 4, 3, '#3a5a5e');
  p.vline(6, 11, 4, '#4a7076');
  p.speckle(2, 6, 12, 6, '#1a2a2c', 5, 19);
  p.glow(10, 7, 2.6, P.toxic, 0.3, 3);                      // bioluminescent moss patch, breathes life into the rock
  p.ellipse(10, 7, 2.6, 1.8, P.moss); p.ellipse(10, 7, 1.6, 1, lighten(P.moss, 0.15));
  p.glow(5, 11, 1.8, P.green, 0.25, 2);
  p.ellipse(5, 11, 1.8, 1.2, darken(P.moss, 0.05));
  p.px(10, 6, lighten(P.toxic, 0.2));
  p.outline(P.ink);
}, { anchor: 'feet' });

defineSprite('bdx_cavern_brokenstalactite', 14, 22, (p) => { // fallen/leaning fragment, jagged snapped-off top
  p.softShadow(8, 20, 6, 1.8, 0.42);
  p.ellipse(8, 20, 6, 2.2, '#1a2a2c');
  p.line(9, 20, 4, 5, '#2e4a4e'); p.line(9, 20, 8, 4, '#3a5a5e');
  p.rect(5, 13, 6, 7, '#243638'); p.rect(6, 9, 5, 6, '#2e4a4e');
  p.vline(9, 14, 8, '#4a7076');                             // wet sheen along the lean
  p.line(4, 5, 6, 3, '#1a2a2c'); p.line(6, 3, 8, 6, '#1a2a2c'); p.line(8, 4, 10, 6, '#1a2a2c');
  p.px(5, 4, lighten('#4a7076', 0.1)); p.px(9, 5, '#6fa0a6');
  p.speckle(5, 10, 6, 8, '#1a2a2c', 4, 58);
  p.outline(P.ink);
}, { anchor: 'feet' });

defineAnim('bdx_cavern_geode', 18, 16, 2, (p, f) => {       // split boulder, crystal cluster inside (cluster filler)
  p.softShadow(9, 15, 7, 2, 0.42);
  p.ellipse(6, 11, 5, 4, '#243638'); p.ellipse(12, 11, 5, 4, '#2e4a4e');
  p.ellipse(6, 10, 4, 3, '#1a2a2c'); p.ellipse(12, 10, 4, 3, '#1a2a2c');
  p.line(6, 12, 6, 6, P.shardD); p.line(8, 12, 9, 5, P.shard); p.line(10, 12, 10, 7, P.shardD);
  p.line(12, 12, 13, 6, P.shard); p.line(11, 12, 12, 8, P.shardD);
  p.glow(9, 8, 3 + f, P.shard, 0.4, 3);
  p.px(9, 5, P.shardL); p.px(13, 6, lighten(P.shard, 0.2));
  if (f === 1) p.star4(9, 6, 2, P.shardL, P.white);
  p.speckle(3, 10, 4, 3, '#4a7076', 3, 61); p.speckle(11, 10, 4, 3, '#4a7076', 3, 62);
  p.outline(P.ink);
}, { anchor: 'feet', fps: 2 });

// ---------------------------------------------------------------------------
// (c) registration
// ---------------------------------------------------------------------------

registerDecals('cavern', [
  'decal_cavern_crumble', 'decal_cavern_vein', 'decal_cavern_puddle', 'decal_cavern_shardbits',
  'decal_cavern_mossline', 'decal_cavern_pebbles', 'decal_cavern_drip', 'decal_cavern_glintdust',
]);
(DECOR_SETS['cavern'] = DECOR_SETS['cavern'] || []).push(
  'bdx_cavern_shardlet', 'bdx_cavern_mossstone', 'bdx_cavern_brokenstalactite', 'bdx_cavern_geode'
);
(DECOR_CLUSTERS['cavern'] = DECOR_CLUSTERS['cavern'] || []).push(
  'bdx_cavern_shardlet', 'bdx_cavern_geode'
);

